catalog_script_client.script:
function onLoad() {
    //Type appropriate comment here, and begin script below
    try {
        // 2. GlideAjaxでサーバー側にFlow実行をリクエスト（クライアント側から直接Flow実行不可）
        var util = new GlideAjax('x_846092_test.CatalogFlowScriptManager');
        util.addParam('sysparm_name', 'executeAutoSwitch');
        //util.addParam('sysparm_name', 'getDecisionTableResults');

        // 3. 同期実行（フォーム送信前にFlowを完了させる場合）
        util.getXMLAnswer(function(response) {
            alert('Flow実行結果：' + response);
/*            var result = JSON.parse(response);
            var u_reco_pro_id = result.u_reco_pro_id;
            var u_script_name = result.u_script_name;
            var u_flow_name = result.u_flow_name;
            g_form.setValue('u_reco_pro_id', u_reco_pro_id);
            g_form.setValue('u_script_name', u_script_name);
            g_form.setValue('u_flow_name', u_flow_name);
            alert('u_reco_pro_id' + u_reco_pro_id);
            alert('u_script_name' + u_script_name);
            alert('u_flow_name' + u_flow_name);*/
            if (response === 'error') {
                g_form.addErrorMessage('Flowの実行に失敗しました');
            }
        });
    } catch (e) {
        g_form.addErrorMessage('処理に失敗しました');
        return false;
    }
}
